import{_ as e,o as r,c as o,f as c}from"./app.cc8f21a4.js";const D=JSON.parse('{"title":"Docker \u4ECB\u7ECD","description":"","frontmatter":{"title":"Docker \u4ECB\u7ECD","date":"2022-01-08T00:00:00.000Z","categories":["\u5F00\u53D1\u5DE5\u5177"],"tags":["Docker"],"meta":[{"name":"description","content":"Docker\u4ECB\u7ECD"},{"name":"keywords","content":"docker,docker\u4ECB\u7ECD,docker\u5BB9\u5668,docker\u955C\u50CF,docker\u4ED3\u5E93"}]},"headers":[{"level":3,"title":"\u4E00\u3001Docker \u4EA7\u751F\u7684\u80CC\u666F","slug":"\u4E00\u3001docker-\u4EA7\u751F\u7684\u80CC\u666F","link":"#\u4E00\u3001docker-\u4EA7\u751F\u7684\u80CC\u666F","children":[]},{"level":3,"title":"\u4E8C\u3001Docker \u7684\u7406\u5FF5","slug":"\u4E8C\u3001docker-\u7684\u7406\u5FF5","link":"#\u4E8C\u3001docker-\u7684\u7406\u5FF5","children":[]},{"level":3,"title":"\u4E09\u3001Docker \u662F\u4EC0\u4E48","slug":"\u4E09\u3001docker-\u662F\u4EC0\u4E48","link":"#\u4E09\u3001docker-\u662F\u4EC0\u4E48","children":[]},{"level":3,"title":"\u56DB\u3001Docker \u80FD\u5E72\u4EC0\u4E48","slug":"\u56DB\u3001docker-\u80FD\u5E72\u4EC0\u4E48","link":"#\u56DB\u3001docker-\u80FD\u5E72\u4EC0\u4E48","children":[]},{"level":3,"title":"\u53BB\u54EA\u4E0B","slug":"\u53BB\u54EA\u4E0B","link":"#\u53BB\u54EA\u4E0B","children":[]},{"level":3,"title":"\u4E94\u3001Docker \u4E09\u8981\u7D20","slug":"\u4E94\u3001docker-\u4E09\u8981\u7D20","link":"#\u4E94\u3001docker-\u4E09\u8981\u7D20","children":[]}],"relativePath":"contents/DevTools/Docker/\u4ECB\u7ECD.md"}'),a={name:"contents/DevTools/Docker/\u4ECB\u7ECD.md"},t=c('<p>Docker \u662F\u57FA\u4E8E Go \u8BED\u8A00\u5B9E\u73B0\u7684\u4E91\u5F00\u6E90\u9879\u76EE</p><h3 id="\u4E00\u3001docker-\u4EA7\u751F\u7684\u80CC\u666F" tabindex="-1">\u4E00\u3001Docker \u4EA7\u751F\u7684\u80CC\u666F <a class="header-anchor" href="#\u4E00\u3001docker-\u4EA7\u751F\u7684\u80CC\u666F" aria-hidden="true">#</a></h3><p>Docker \u662F\u4E3A\u89E3\u51B3\u4ECE\u5F00\u53D1\u5230\u8FD0\u7EF4\u90E8\u7F72\uFF0C\u56E0\u64CD\u4F5C\u7CFB\u7EDF\u3001\u8FD0\u884C\u73AF\u5883\u3001\u5E94\u7528\u914D\u7F6E\u4E0D\u540C\uFF0C\u800C\u5BFC\u81F4\u65E0\u6CD5\u987A\u5229\u90E8\u7F72\u6210\u529F\u7684\u95EE\u9898\u6240\u5E94\u8FD0\u800C\u751F\u7684\u4E00\u4E2A\u6807\u51C6\u5316\u89E3\u51B3\u65B9\u6848\u3002</p><p>\u5373\u8F6F\u4EF6\u5E26\u73AF\u5883\u5B89\u88C5\u3002\u901A\u8FC7\u955C\u50CF(images)\u5C06\u4F5C\u4E1A\u7CFB\u7EDF\u6838\u5FC3\u9664\u5916\uFF0C\u8FD0\u4F5C\u5E94\u7528\u7A0B\u5F0F\u6240\u9700\u8981\u7684\u7CFB\u7EDF\u73AF\u5883\uFF0C\u7531\u4E0B\u800C\u4E0A\u6253\u5305\u3002\u6765\u8FBE\u5230\u5E94\u7528\u7A0B\u5F0F\u8DE8\u5E73\u53F0\u95F4\u7684\u65E0\u7F1D\u63A5\u8F68\u8FD0\u4F5C\uFF0C\u4E00\u6B21\u6784\u5EFA\u5904\u5904\u8FD0\u884C\u7684\u76EE\u7684\u3002</p><h3 id="\u4E8C\u3001docker-\u7684\u7406\u5FF5" tabindex="-1">\u4E8C\u3001Docker \u7684\u7406\u5FF5 <a class="header-anchor" href="#\u4E8C\u3001docker-\u7684\u7406\u5FF5" aria-hidden="true">#</a></h3><p>\u4E00\u6B21\u5C01\u88C5\uFF0C\u5230\u5904\u8FD0\u884C\u3002</p><h3 id="\u4E09\u3001docker-\u662F\u4EC0\u4E48" tabindex="-1">\u4E09\u3001Docker \u662F\u4EC0\u4E48 <a class="header-anchor" href="#\u4E09\u3001docker-\u662F\u4EC0\u4E48" aria-hidden="true">#</a></h3><p>\u89E3\u51B3\u4E86\u8FD0\u884C\u73AF\u5883\u548C\u914D\u7F6E\u95EE\u9898\u7684\u8F6F\u4EF6\u5BB9\u5668\uFF0C\u65B9\u4FBF\u505A\u6301\u7EED\u96C6\u6210\u5E76\u6709\u52A9\u4E8E\u6574\u4F53\u53D1\u5E03\u7684\u5BB9\u5668\u865A\u62DF\u5316\u6280\u672F\u3002</p><h3 id="\u56DB\u3001docker-\u80FD\u5E72\u4EC0\u4E48" tabindex="-1">\u56DB\u3001Docker \u80FD\u5E72\u4EC0\u4E48 <a class="header-anchor" href="#\u56DB\u3001docker-\u80FD\u5E72\u4EC0\u4E48" aria-hidden="true">#</a></h3><p>\u5F00\u53D1/\u8FD0\u7EF4(DevOps)</p><p>\u2460 \u66F4\u5FEB\u901F\u7684\u5E94\u7528\u4EA4\u4ED8\u548C\u90E8\u7F72</p><p>\u2461 \u66F4\u4FBF\u6377\u7684\u5347\u7EA7\u548C\u6269\u7F29\u5BB9</p><p>\u2462 \u66F4\u7B80\u5355\u7684\u7CFB\u7EDF\u8FD0\u7EF4</p><p>\u2463 \u66F4\u9AD8\u6548\u7684\u8BA1\u7B97\u8D44\u6E90\u5229\u7528</p><p>\u4F18\u52BF\uFF1A</p><p>\xB7 \u8F7B\u91CF\u3001\u79D2\u7EA7\u7684\u5FEB\u901F\u542F\u52A8\u901F\u5EA6</p><p>\xB7 \u7B80\u5355\uFF0C\u6613\u7528\u3001\u6D3B\u8DC3\u7684\u793E\u533A</p><p>\xB7 \u6807\u51C6\u7EDF\u4E00\u7684\u6253\u5305/\u90E8\u7F72/\u8FD0\u884C\u65B9\u6848</p><p>\xB7 \u955C\u50CF\u652F\u6301\u589E\u91CF\u5206\u53D1\uFF0C\u6613\u4E8E\u90E8\u7F72</p><p>\xB7 \u6613\u4E8E\u6784\u5EFA\uFF0C\u826F\u597D\u7684 REST API\uFF0C\u4E5F\u5F88\u9002\u5408\u81EA\u52A8\u5316\u6D4B\u8BD5\u548C\u6301\u7EED\u96C6\u6210</p><p>\xB7 \u6027\u80FD\uFF0C\u5C24\u5176\u662F\u5185\u5B58\u548C IO \u7684\u5F00\u9500</p><h3 id="\u53BB\u54EA\u4E0B" tabindex="-1">\u53BB\u54EA\u4E0B <a class="header-anchor" href="#\u53BB\u54EA\u4E0B" aria-hidden="true">#</a></h3><p>\u5B98\u7F51\uFF1A<a href="http://www.docker.com" target="_blank" rel="noreferrer">http://www.docker.com</a> \u4E2D\u6587\u7F51\u7AD9\uFF1A<a href="https://www.docker-cn.com" target="_blank" rel="noreferrer">https://www.docker-cn.com</a></p><p>\u4ED3\u5E93 Docker Hub\uFF1A<a href="https://hub.docker.com" target="_blank" rel="noreferrer">https://hub.docker.com</a></p><h3 id="\u4E94\u3001docker-\u4E09\u8981\u7D20" tabindex="-1">\u4E94\u3001Docker \u4E09\u8981\u7D20 <a class="header-anchor" href="#\u4E94\u3001docker-\u4E09\u8981\u7D20" aria-hidden="true">#</a></h3><p>\u955C\u50CF(images)\u3001\u5BB9\u5668(container)\u3001\u4ED3\u5E93(repository)</p><p>\u955C\u50CF\u662F\u4E00\u4E2A\u53EA\u8BFB\u7684\u6A21\u677F\u3002\u955C\u50CF\u53EF\u4EE5\u7528\u6765\u521B\u5EFA Docker \u5BB9\u5668\uFF0C\u4E00\u4E2A\u955C\u50CF\u53EF\u4EE5\u521B\u5EFA\u5F88\u591A\u5BB9\u5668\u3002</p><p>\u5BB9\u5668\u662F\u7528\u955C\u50CF\u521B\u5EFA\u7684\u8FD0\u884C\u5B9E\u4F8B\uFF0C\u72EC\u7ACB\u8FD0\u884C\u4E00\u4E2A\u6216\u4E00\u7EC4\u3002\u53EF\u4EE5\u88AB\u542F\u52A8\u3001\u5F00\u59CB\u3001\u505C\u6B62\u3001\u5220\u9664\u3002\u6BCF\u4E2A\u5BB9\u5668\u90FD\u662F\u76F8\u4E92\u9694\u79BB\u3002\u53EF\u4EE5\u628A\u5BB9\u5668\u770B\u505A\u662F\u4E00\u4E2A\u7B80\u6613\u7248\u7684 linux \u73AF\u5883(\u5305\u62EC root \u7528\u6237\u6743\u9650\u3001\u8FDB\u7A0B\u7A7A\u95F4\u3001\u7528\u6237\u7A7A\u95F4\u548C\u7F51\u7EDC\u7A7A\u95F4\u7B49)\u548C\u8FD0\u884C\u5728\u5176\u4E2D\u7684\u5E94\u7528\u7A0B\u5E8F\u3002 \u5BB9\u5668\u7684\u5B9A\u4E49\u548C\u955C\u50CF\u51E0\u4E4E\u4E00\u6A21\u4E00\u6837\uFF0C\u4E5F\u662F\u4E00\u5806\u5C42\u7684\u7EDF\u4E00\u89C6\u89D2\uFF0C\u552F\u4E00\u533A\u522B\u5728\u4E8E\u5BB9\u5668\u7684\u6700\u4E0A\u9762\u90A3\u4E00\u5C42\u662F\u53EF\u8BFB\u53EF\u5199\u7684\u3002</p><p>\u4ED3\u5E93\u662F\u96C6\u4E2D\u5B58\u653E\u955C\u50CF\u6587\u4EF6\u7684\u573A\u6240\u3002</p><p>\u4ED3\u5E93(repository)\u548C\u4ED3\u5E93\u6CE8\u518C\u670D\u52A1\u5668(registry)\u662F\u6709\u533A\u522B\u7684\u3002\u4ED3\u5E93\u6CE8\u518C\u670D\u52A1\u5668\u4E0A\u5F80\u5F80\u5B58\u653E\u7740\u591A\u4E2A\u4ED3\u5E93\uFF0C\u6BCF\u4E2A\u4ED3\u5E93\u4E2D\u53C8\u5305\u542B\u4E86\u591A\u4E2A\u955C\u50CF\uFF0C\u6BCF\u4E2A\u955C\u50CF\u6709\u4E0D\u540C\u7684\u6807\u7B7E(tag)\u3002</p><p>\u4ED3\u5E93\u5206\u4E3A\u516C\u5F00\u4ED3\u5E93(public)\u548C\u79C1\u6709\u4ED3\u5E93(private)\u4E24\u79CD\u5F62\u5F0F\u3002</p><p>\u9700\u8981\u6B63\u786E\u7684\u7406\u89E3\u4ED3\u5E93/\u955C\u50CF/\u5BB9\u5668\u8FD9\u51E0\u4E2A\u6982\u5FF5\uFF1A</p><p>Docker \u672C\u8EAB\u662F\u4E00\u4E2A\u5BB9\u5668\u8FD0\u884C\u8F7D\u4F53\u6216\u79F0\u4E4B\u4E3A\u7BA1\u7406\u5F15\u64CE\u3002\u6211\u4EEC\u628A\u5E94\u7528\u7A0B\u5E8F\u548C\u914D\u7F6E\u4F9D\u8D56\u6253\u5305\u597D\u5F62\u6210\u4E00\u4E2A\u53EF\u4EA4\u4ED8\u7684\u8FD0\u884C\u73AF\u5883\uFF0C\u8FD9\u4E2A\u6253\u5305\u597D\u7684\u8FD0\u884C\u73AF\u5883\u5C31\u4F3C\u4E4E images \u955C\u50CF\u6587\u4EF6\u3002\u53EA\u6709\u901A\u8FC7\u8FD9\u4E2A\u955C\u50CF\u6587\u4EF6\u624D\u80FD\u751F\u6210 Docker \u5BB9\u5668\u3002image \u6587\u4EF6\u53EF\u4EE5\u770B\u505A\u662F\u5BB9\u5668\u7684\u6A21\u677F\u3002docker \u6839\u636E image \u6587\u4EF6\u751F\u6210\u5BB9\u5668\u7684\u5B9E\u4F8B\u3002\u540C\u4E00\u4E2A image \u6587\u4EF6\uFF0C\u53EF\u4EE5\u751F\u6210\u591A\u4E2A\u540C\u4E8B\u8FD0\u884C\u7684\u5BB9\u5668\u5B9E\u4F8B\u3002</p><p>\u4E00\u4E2A\u5BB9\u5668\u8FD0\u884C\u4E00\u79CD\u670D\u52A1\uFF0C\u5F53\u6211\u4EEC\u9700\u8981\u7684\u65F6\u5019\uFF0C\u5C31\u53EF\u4EE5\u901A\u8FC7 docker \u5BA2\u6237\u7AEF\u521B\u5EFA\u4E00\u4E2A\u5BF9\u5E94\u7684\u8FD0\u884C\u5B9E\u4F8B\uFF0C\u4E5F\u5C31\u662F\u6211\u4EEC\u7684\u5BB9\u5668\u3002</p><p>\u81F3\u4E8E\u4ED3\u5E93\uFF0C\u5C31\u662F\u653E\u4E86\u4E00\u5806\u955C\u50CF\u7684\u5730\u65B9\uFF0C\u6211\u4EEC\u53EF\u4EE5\u628A\u955C\u50CF\u53D1\u5E03\u5230\u4ED3\u5E93\u4E2D\uFF0C\u9700\u8981\u7684\u65F6\u5019\u4ECE\u4ED3\u5E93\u4E2D\u62C9\u4E0B\u6765\u5C31\u53EF\u4EE5\u4E86\u3002</p>',35),d=[t];function p(i,n,k,l,h,s){return r(),o("div",null,d)}const m=e(a,[["render",p]]);export{D as __pageData,m as default};
